 43→var (
 44→	configPath string
 45→	config     *CombinedConfig
 46→
 47→	rootCmd = &cobra.Command{
 48→		Use:   "combined",
 49→		Short: "Combined Netbird server (Management + Signal + Relay + STUN)",
 50→		Long: `Combined Netbird server for self-hosted deployments.
 51→
 52→All services (Management, Signal, Relay) are multiplexed on a single port.
 53→Optional STUN server runs on separate UDP ports.
 54→
 55→Configuration is loaded from a YAML file specified with --config.`,
 56→		SilenceUsage:  true,
 57→		SilenceErrors: true,
 58→		RunE:          execute,
 59→	}
 60→)
 61→
 62→func init() {
 63→	rootCmd.PersistentFlags().StringVarP(&configPath, "config", "c", "", "path to YAML configuration file (required)")
 64→	_ = rootCmd.MarkPersistentFlagRequired("config")
 65→
 66→	rootCmd.AddCommand(newTokenCommands())
 67→}
 68→
 69→func Execute() error {
 70→	return rootCmd.Execute()
 71→}
 72→
 73→func waitForExitSignal() {
 74→	osSigs := make(chan os.Signal, 1)
 75→	signal.Notify(osSigs, syscall.SIGINT, syscall.SIGTERM)
 76→	<-osSigs
 77→}
 78→
 79→func execute(cmd *cobra.Command, _ []string) error {
 80→	if err := initializeConfig(); err != nil {
 81→		return err
 82→	}
 83→
 84→	// Management is required as the base server when signal or relay are enabled
 85→	if (config.Signal.Enabled || config.Relay.Enabled) && !config.Management.Enabled {
 86→		return fmt.Errorf("management must be enabled when signal or relay are enabled (provides the base HTTP server)")
 87→	}
 88→
 89→	servers, err := createAllServers(cmd.Context(), config)
 90→	if err != nil {
 91→		return err
 92→	}
 93→
 94→	// Register services with management's gRPC server using AfterInit hook
 95→	setupServerHooks(servers, config)
 96→
 97→	// Start management server (this also starts the HTTP listener)
 98→	if servers.mgmtSrv != nil {
 99→		if err := servers.mgmtSrv.Start(cmd.Context()); err != nil {
100→			cleanupSTUNListeners(servers.stunListeners)
101→			return fmt.Errorf("failed to start management server: %w", err)
102→		}
103→	}
104→
105→	// Start all other servers
106→	wg := sync.WaitGroup{}
107→	startServers(&wg, servers.relaySrv, servers.healthcheck, servers.stunServer, servers.metricsServer)
108→
109→	waitForExitSignal()
110→
111→	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
112→	defer cancel()
113→
114→	err = shutdownServers(ctx, servers.relaySrv, servers.healthcheck, servers.stunServer, servers.mgmtSrv, servers.metricsServer)
115→	wg.Wait()
116→	return err
117→}
