119→// initializeConfig loads and validates the configuration, then initializes logging.
120→func initializeConfig() error {
121→	var err error
122→	config, err = LoadConfig(configPath)
123→	if err != nil {
124→		return fmt.Errorf("failed to load config: %w", err)
125→	}
126→
127→	if err := config.Validate(); err != nil {
128→		return fmt.Errorf("invalid config: %w", err)
129→	}
130→
131→	if err := util.InitLog(config.Server.LogLevel, config.Server.LogFile); err != nil {
132→		return fmt.Errorf("failed to initialize log: %w", err)
133→	}
134→
135→	if dsn := config.Server.Store.DSN; dsn != "" {
136→		switch strings.ToLower(config.Server.Store.Engine) {
137→		case "postgres":
138→			os.Setenv("NB_STORE_ENGINE_POSTGRES_DSN", dsn)
139→		case "mysql":
140→			os.Setenv("NB_STORE_ENGINE_MYSQL_DSN", dsn)
141→		}
142→	}
143→
144→	if engine := config.Server.ActivityStore.Engine; engine != "" {
145→		engineLower := strings.ToLower(engine)
146→		if engineLower == "postgres" && config.Server.ActivityStore.DSN == "" {
147→			return fmt.Errorf("activityStore.dsn is required when activityStore.engine is postgres")
148→		}
149→		os.Setenv("NB_ACTIVITY_EVENT_STORE_ENGINE", engineLower)
150→		if dsn := config.Server.ActivityStore.DSN; dsn != "" {
151→			os.Setenv("NB_ACTIVITY_EVENT_POSTGRES_DSN", dsn)
152→		}
153→	}
154→
155→	log.Infof("Starting combined NetBird server")
156→	logConfig(config)
157→	logEnvVars()
158→	return nil
159→}
