161→// serverInstances holds all server instances created during startup.
162→type serverInstances struct {
163→	relaySrv      *relayServer.Server
164→	mgmtSrv       *mgmtServer.BaseServer
165→	signalSrv     *signalServer.Server
166→	healthcheck   *healthcheck.Server
167→	stunServer    *stun.Server
168→	stunListeners []*net.UDPConn
169→	metricsServer *sharedMetrics.Metrics
170→}
