172→// createAllServers creates all server instances based on configuration.
173→func createAllServers(ctx context.Context, cfg *CombinedConfig) (*serverInstances, error) {
174→	metricsServer, err := sharedMetrics.NewServer(cfg.Server.MetricsPort, "")
175→	if err != nil {
176→		return nil, fmt.Errorf("failed to create metrics server: %w", err)
177→	}
178→	servers := &serverInstances{
179→		metricsServer: metricsServer,
180→	}
181→
182→	_, tlsSupport, err := handleTLSConfig(cfg)
183→	if err != nil {
184→		return nil, fmt.Errorf("failed to setup TLS config: %w", err)
185→	}
186→
187→	if err := servers.createRelayServer(cfg, tlsSupport); err != nil {
188→		return nil, err
189→	}
190→
191→	if err := servers.createManagementServer(ctx, cfg); err != nil {
192→		return nil, err
193→	}
194→
195→	if err := servers.createSignalServer(ctx, cfg); err != nil {
196→		return nil, err
197→	}
198→
199→	if err := servers.createHealthcheckServer(cfg); err != nil {
200→		return nil, err
201→	}
202→
203→	return servers, nil
204→}
