206→func (s *serverInstances) createRelayServer(cfg *CombinedConfig, tlsSupport bool) error {
207→	if !cfg.Relay.Enabled {
208→		return nil
209→	}
210→
211→	var err error
212→	s.stunListeners, err = createSTUNListeners(cfg)
213→	if err != nil {
214→		return err
215→	}
216→
217→	hashedSecret := sha256.Sum256([]byte(cfg.Relay.AuthSecret))
218→	authenticator := auth.NewTimedHMACValidator(hashedSecret[:], 24*time.Hour)
219→
220→	relayCfg := relayServer.Config{
221→		Meter:          s.metricsServer.Meter,
222→		ExposedAddress: cfg.Relay.ExposedAddress,
223→		AuthValidator:  authenticator,
224→		TLSSupport:     tlsSupport,
225→	}
226→
227→	s.relaySrv, err = createRelayServer(relayCfg, s.stunListeners)
228→	if err != nil {
229→		return err
230→	}
231→
232→	log.Infof("Relay server created")
233→
234→	if len(s.stunListeners) > 0 {
235→		s.stunServer = stun.NewServer(s.stunListeners, cfg.Relay.Stun.LogLevel)
236→	}
237→
238→	return nil
239→}
