241→func (s *serverInstances) createManagementServer(ctx context.Context, cfg *CombinedConfig) error {
242→	if !cfg.Management.Enabled {
243→		return nil
244→	}
245→
246→	mgmtConfig, err := cfg.ToManagementConfig()
247→	if err != nil {
248→		return fmt.Errorf("failed to create management config: %w", err)
249→	}
250→
251→	_, portStr, portErr := net.SplitHostPort(cfg.Server.ListenAddress)
252→	if portErr != nil {
253→		portStr = "443"
254→	}
255→	mgmtPort, _ := strconv.Atoi(portStr)
256→
257→	if err := ApplyEmbeddedIdPConfig(ctx, mgmtConfig, mgmtPort, false); err != nil {
258→		cleanupSTUNListeners(s.stunListeners)
259→		return fmt.Errorf("failed to apply embedded IdP config: %w", err)
260→	}
261→
262→	if err := EnsureEncryptionKey(ctx, mgmtConfig); err != nil {
263→		cleanupSTUNListeners(s.stunListeners)
264→		return fmt.Errorf("failed to ensure encryption key: %w", err)
265→	}
266→
267→	LogConfigInfo(mgmtConfig)
268→
269→	s.mgmtSrv, err = createManagementServer(cfg, mgmtConfig)
270→	if err != nil {
271→		cleanupSTUNListeners(s.stunListeners)
272→		return fmt.Errorf("failed to create management server: %w", err)
273→	}
274→
275→	// Inject externally-managed AppMetrics so management uses the shared metrics server
276→	appMetrics, err := telemetry.NewAppMetricsWithMeter(ctx, s.metricsServer.Meter)
277→	if err != nil {
278→		cleanupSTUNListeners(s.stunListeners)
279→		return fmt.Errorf("failed to create management app metrics: %w", err)
280→	}
281→	mgmtServer.Inject[telemetry.AppMetrics](s.mgmtSrv, appMetrics)
282→
283→	log.Infof("Management server created")
284→	return nil
285→}
