303→func (s *serverInstances) createHealthcheckServer(cfg *CombinedConfig) error {
304→	hCfg := healthcheck.Config{
305→		ListenAddress:  cfg.Server.HealthcheckAddress,
306→		ServiceChecker: s.relaySrv,
