314→// setupServerHooks registers services with management's gRPC server.
315→func setupServerHooks(servers *serverInstances, cfg *CombinedConfig) {
316→	if servers.mgmtSrv == nil {
317→		return
318→	}
319→
320→	servers.mgmtSrv.AfterInit(func(s *mgmtServer.BaseServer) {
321→		grpcSrv := s.GRPCServer()
322→
323→		if servers.signalSrv != nil {
324→			proto.RegisterSignalExchangeServer(grpcSrv, servers.signalSrv)
325→			log.Infof("Signal server registered on port %s", cfg.Server.ListenAddress)
326→		}
327→
328→		s.SetHandlerFunc(createCombinedHandler(grpcSrv, s.APIHandler(), servers.relaySrv, servers.metricsServer.Meter, cfg))
329→		if servers.relaySrv != nil {
330→			log.Infof("Relay WebSocket handler added (path: /relay)")
331→		}
332→	})
333→}
