335→func startServers(wg *sync.WaitGroup, srv *relayServer.Server, httpHealthcheck *healthcheck.Server, stunServer *stun.Server, metricsServer *sharedMetrics.Metrics) {
336→	if srv != nil {
337→		instanceURL := srv.InstanceURL()
338→		log.Infof("Relay server instance URL: %s", instanceURL.String())
339→		log.Infof("Relay WebSocket multiplexed on management port (no separate relay listener)")
340→	}
341→
342→	wg.Add(1)
343→	go func() {
344→		defer wg.Done()
345→		log.Infof("running metrics server: %s%s", metricsServer.Addr, metricsServer.Endpoint)
346→		if err := metricsServer.ListenAndServe(); !errors.Is(err, http.ErrServerClosed) {
347→			log.Fatalf("failed to start metrics server: %v", err)
348→		}
349→	}()
350→
351→	wg.Add(1)
352→	go func() {
353→		defer wg.Done()
354→		if err := httpHealthcheck.ListenAndServe(); !errors.Is(err, http.ErrServerClosed) {
355→			log.Fatalf("failed to start healthcheck server: %v", err)
356→		}
357→	}()
358→
359→	if stunServer != nil {
360→		wg.Add(1)
361→		go func() {
362→			defer wg.Done()
363→			if err := stunServer.Listen(); err != nil {
364→				if errors.Is(err, stun.ErrServerClosed) {
365→					return
366→				}
367→				log.Errorf("STUN server error: %v", err)
368→			}
369→		}()
370→	}
371→}
