373→func shutdownServers(ctx context.Context, srv *relayServer.Server, httpHealthcheck *healthcheck.Server, stunServer *stun.Server, mgmtSrv *mgmtServer.BaseServer, metricsServer *sharedMetrics.Metrics) error {
374→	var errs error
375→
376→	if err := httpHealthcheck.Shutdown(ctx); err != nil {
377→		errs = multierror.Append(errs, fmt.Errorf("failed to close healthcheck server: %w", err))
378→	}
379→
380→	if stunServer != nil {
381→		if err := stunServer.Shutdown(); err != nil {
382→			errs = multierror.Append(errs, fmt.Errorf("failed to close STUN server: %w", err))
383→		}
384→	}
385→
386→	if srv != nil {
387→		if err := srv.Shutdown(ctx); err != nil {
388→			errs = multierror.Append(errs, fmt.Errorf("failed to close relay server: %w", err))
389→		}
390→	}
391→
392→	if mgmtSrv != nil {
393→		log.Infof("shutting down management and signal servers")
394→		if err := mgmtSrv.Stop(); err != nil {
395→			errs = multierror.Append(errs, fmt.Errorf("failed to close management server: %w", err))
396→		}
397→	}
398→
399→	if metricsServer != nil {
400→		log.Infof("shutting down metrics server")
401→		if err := metricsServer.Shutdown(ctx); err != nil {
402→			errs = multierror.Append(errs, fmt.Errorf("failed to close metrics server: %w", err))
403→		}
404→	}
405→
406→	return errs
407→}
