409→func createHealthCheck(hCfg healthcheck.Config, stunListeners []*net.UDPConn) (*healthcheck.Server, error) {
410→	httpHealthcheck, err := healthcheck.NewServer(hCfg)
411→	if err != nil {
412→		cleanupSTUNListeners(stunListeners)
413→		return nil, fmt.Errorf("failed to create healthcheck server: %w", err)
414→	}
415→	return httpHealthcheck, nil
416→}
