433→func createSTUNListeners(cfg *CombinedConfig) ([]*net.UDPConn, error) {
434→	var stunListeners []*net.UDPConn
435→	if cfg.Relay.Stun.Enabled {
436→		for _, port := range cfg.Relay.Stun.Ports {
437→			listener, err := net.ListenUDP("udp", &net.UDPAddr{Port: port})
438→			if err != nil {
439→				cleanupSTUNListeners(stunListeners)
440→				return nil, fmt.Errorf("failed to create STUN listener on port %d: %w", port, err)
441→			}
442→			stunListeners = append(stunListeners, listener)
443→			log.Infof("STUN server listening on UDP port %d", port)
444→		}
445→	}
446→	return stunListeners, nil
447→}
