487→func createManagementServer(cfg *CombinedConfig, mgmtConfig *nbconfig.Config) (*mgmtServer.BaseServer, error) {
488→	mgmt := cfg.Management
489→
490→	dnsDomain := mgmt.DnsDomain
491→	singleAccModeDomain := dnsDomain
492→
493→	// Extract port from listen address
494→	_, portStr, err := net.SplitHostPort(cfg.Server.ListenAddress)
495→	if err != nil {
496→		// If no port specified, assume default
497→		portStr = "443"
498→	}
499→	mgmtPort, _ := strconv.Atoi(portStr)
500→
501→	mgmtSrv := mgmtServer.NewServer(
502→		&mgmtServer.Config{
503→			NbConfig:                mgmtConfig,
504→			DNSDomain:               dnsDomain,
505→			MgmtSingleAccModeDomain: singleAccModeDomain,
506→			MgmtPort:                mgmtPort,
507→			MgmtMetricsPort:         cfg.Server.MetricsPort,
508→			DisableMetrics:          mgmt.DisableAnonymousMetrics,
509→			DisableGeoliteUpdate:    mgmt.DisableGeoliteUpdate,
510→			// Always enable user deletion from IDP in combined server (embedded IdP is always enabled)
511→			UserDeleteFromIDPEnabled: true,
512→		},
513→	)
514→
515→	return mgmtSrv, nil
516→}
