518→// createCombinedHandler creates an HTTP handler that multiplexes Management, Signal (via wsproxy), and Relay WebSocket traffic
519→func createCombinedHandler(grpcServer *grpc.Server, httpHandler http.Handler, relaySrv *relayServer.Server, meter metric.Meter, cfg *CombinedConfig) http.Handler {
520→	wsProxy := wsproxyserver.New(grpcServer, wsproxyserver.WithOTelMeter(meter))
521→
522→	var relayAcceptFn func(conn net.Conn)
523→	if relaySrv != nil {
524→		relayAcceptFn = relaySrv.RelayAccept()
525→	}
526→
527→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
528→		switch {
529→		// Native gRPC traffic (HTTP/2 with gRPC content-type)
530→		case r.ProtoMajor == 2 && (strings.HasPrefix(r.Header.Get("Content-Type"), "application/grpc") ||
531→			strings.HasPrefix(r.Header.Get("Content-Type"), "application/grpc+proto")):
532→			grpcServer.ServeHTTP(w, r)
533→
534→		// WebSocket proxy for Management gRPC
535→		case r.URL.Path == wsproxy.ProxyPath+wsproxy.ManagementComponent:
536→			wsProxy.Handler().ServeHTTP(w, r)
537→
538→		// WebSocket proxy for Signal gRPC
539→		case r.URL.Path == wsproxy.ProxyPath+wsproxy.SignalComponent:
540→			if cfg.Signal.Enabled {
541→				wsProxy.Handler().ServeHTTP(w, r)
542→			} else {
543→				http.Error(w, "Signal service not enabled", http.StatusNotFound)
544→			}
545→
546→		// Relay WebSocket
547→		case r.URL.Path == "/relay":
548→			if relayAcceptFn != nil {
549→				handleRelayWebSocket(w, r, relayAcceptFn, cfg)
550→			} else {
551→				http.Error(w, "Relay service not enabled", http.StatusNotFound)
552→			}
553→
554→		// Management HTTP API (default)
555→		default:
556→			httpHandler.ServeHTTP(w, r)
557→		}
558→	})
559→}
560→
561→// handleRelayWebSocket handles incoming WebSocket connections for the relay service
562→func handleRelayWebSocket(w http.ResponseWriter, r *http.Request, acceptFn func(conn net.Conn), cfg *CombinedConfig) {
563→	acceptOptions := &websocket.AcceptOptions{
564→		OriginPatterns: []string{"*"},
565→	}
566→
567→	wsConn, err := websocket.Accept(w, r, acceptOptions)
568→	if err != nil {
569→		log.Errorf("failed to accept relay ws connection: %s", err)
570→		return
571→	}
572→
573→	connRemoteAddr := r.RemoteAddr
574→	if r.Header.Get("X-Real-Ip") != "" && r.Header.Get("X-Real-Port") != "" {
575→		connRemoteAddr = net.JoinHostPort(r.Header.Get("X-Real-Ip"), r.Header.Get("X-Real-Port"))
576→	}
577→
578→	rAddr, err := net.ResolveTCPAddr("tcp", connRemoteAddr)
579→	if err != nil {
580→		_ = wsConn.Close(websocket.StatusInternalError, "internal error")
581→		return
582→	}
583→
584→	lAddr, err := net.ResolveTCPAddr("tcp", cfg.Server.ListenAddress)
585→	if err != nil {
586→		_ = wsConn.Close(websocket.StatusInternalError, "internal error")
587→		return
588→	}
589→
590→	log.Debugf("Relay WS client connected from: %s", rAddr)
591→
592→	conn := ws.NewConn(wsConn, lAddr, rAddr)
593→	acceptFn(conn)
594→}
