596→// logConfig prints all configuration parameters for debugging
597→func logConfig(cfg *CombinedConfig) {
598→	log.Info("=== Configuration ===")
599→	logServerConfig(cfg)
600→	logComponentsConfig(cfg)
601→	logRelayConfig(cfg)
602→	logManagementConfig(cfg)
603→	log.Info("=== End Configuration ===")
604→}
605→
606→func logServerConfig(cfg *CombinedConfig) {
607→	log.Info("--- Server ---")
608→	log.Infof("  Listen address: %s", cfg.Server.ListenAddress)
609→	log.Infof("  Exposed address: %s", cfg.Server.ExposedAddress)
610→	log.Infof("  Healthcheck address: %s", cfg.Server.HealthcheckAddress)
611→	log.Infof("  Metrics port: %d", cfg.Server.MetricsPort)
612→	log.Infof("  Log level: %s", cfg.Server.LogLevel)
613→	log.Infof("  Data dir: %s", cfg.Server.DataDir)
614→
615→	switch {
616→	case cfg.HasTLSCert():
617→		log.Infof("  TLS: cert=%s, key=%s", cfg.Server.TLS.CertFile, cfg.Server.TLS.KeyFile)
618→	case cfg.HasLetsEncrypt():
619→		log.Infof("  TLS: Let's Encrypt (domains=%v)", cfg.Server.TLS.LetsEncrypt.Domains)
620→	default:
621→		log.Info("  TLS: disabled (using reverse proxy)")
622→	}
623→}
624→
625→func logComponentsConfig(cfg *CombinedConfig) {
626→	log.Info("--- Components ---")
627→	log.Infof("  Management: %v (log level: %s)", cfg.Management.Enabled, cfg.Management.LogLevel)
628→	log.Infof("  Signal: %v (log level: %s)", cfg.Signal.Enabled, cfg.Signal.LogLevel)
629→	log.Infof("  Relay: %v (log level: %s)", cfg.Relay.Enabled, cfg.Relay.LogLevel)
630→}
631→
632→func logRelayConfig(cfg *CombinedConfig) {
633→	if !cfg.Relay.Enabled {
634→		return
635→	}
636→	log.Info("--- Relay ---")
637→	log.Infof("  Exposed address: %s", cfg.Relay.ExposedAddress)
638→	log.Infof("  Auth secret: %s...", maskSecret(cfg.Relay.AuthSecret))
639→	if cfg.Relay.Stun.Enabled {
640→		log.Infof("  STUN ports: %v (log level: %s)", cfg.Relay.Stun.Ports, cfg.Relay.Stun.LogLevel)
641→	} else {
642→		log.Info("  STUN: disabled")
643→	}
644→}
645→
646→func logManagementConfig(cfg *CombinedConfig) {
647→	if !cfg.Management.Enabled {
648→		return
649→	}
650→	log.Info("--- Management ---")
651→	log.Infof("  Data dir: %s", cfg.Management.DataDir)
652→	log.Infof("  DNS domain: %s", cfg.Management.DnsDomain)
653→	log.Infof("  Store engine: %s", cfg.Management.Store.Engine)
654→	if cfg.Server.Store.DSN != "" {
655→		log.Infof("  Store DSN: %s", maskDSNPassword(cfg.Server.Store.DSN))
656→	}
657→
658→	log.Info("  Auth (embedded IdP):")
659→	log.Infof("    Issuer: %s", cfg.Management.Auth.Issuer)
660→	log.Infof("    Dashboard redirect URIs: %v", cfg.Management.Auth.DashboardRedirectURIs)
661→	log.Infof("    CLI redirect URIs: %v", cfg.Management.Auth.CLIRedirectURIs)
662→
663→	log.Info("  Client settings:")
664→	log.Infof("    Signal URI: %s", cfg.Management.SignalURI)
665→	for _, s := range cfg.Management.Stuns {
666→		log.Infof("    STUN: %s", s.URI)
667→	}
668→	if len(cfg.Management.Relays.Addresses) > 0 {
669→		log.Infof("    Relay addresses: %v", cfg.Management.Relays.Addresses)
670→		log.Infof("    Relay credentials TTL: %s", cfg.Management.Relays.CredentialsTTL)
671→	}
672→}
673→
674→// logEnvVars logs all NB_ environment variables that are currently set
675→func logEnvVars() {
676→	log.Info("=== Environment Variables ===")
677→	found := false
678→	for _, env := range os.Environ() {
679→		if strings.HasPrefix(env, "NB_") {
680→			key, _, _ := strings.Cut(env, "=")
681→			value := os.Getenv(key)
682→			keyLower := strings.ToLower(key)
683→			if strings.Contains(keyLower, "secret") || strings.Contains(keyLower, "key") || strings.Contains(keyLower, "password") {
684→				value = maskSecret(value)
685→			} else if strings.Contains(keyLower, "dsn") {
686→				value = maskDSNPassword(value)
687→			}
688→			log.Infof("  %s=%s", key, value)
689→			found = true
690→		}
691→	}
692→	if !found {
693→		log.Info("  (none set)")
694→	}
695→	log.Info("=== End Environment Variables ===")
696→}
697→
698→// maskDSNPassword masks the password in a DSN string.
699→// Handles both key=value format ("password=secret") and URI format ("user:secret@host").
700→func maskDSNPassword(dsn string) string {
701→	// Key=value format: "host=localhost user=nb password=secret dbname=nb"
702→	if strings.Contains(dsn, "password=") {
703→		parts := strings.Fields(dsn)
704→		for i, p := range parts {
705→			if strings.HasPrefix(p, "password=") {
706→				parts[i] = "password=****"
707→			}
708→		}
709→		return strings.Join(parts, " ")
710→	}
711→
712→	// URI format: "user:password@host..."
713→	if atIdx := strings.Index(dsn, "@"); atIdx != -1 {
714→		prefix := dsn[:atIdx]
715→		if colonIdx := strings.Index(prefix, ":"); colonIdx != -1 {
716→			return prefix[:colonIdx+1] + "****" + dsn[atIdx:]
717→		}
718→	}
719→
720→	return dsn
721→}
722→
723→// maskSecret returns first 4 chars of secret followed by "..."
724→func maskSecret(secret string) string {
725→	if len(secret) <= 4 {
726→		return "****"
727→	}
728→	return secret[:4] + "..."
729→}
