 60→			config, err = LoadMgmtConfig(ctx, nbconfig.MgmtConfigPath)
 61→			if err != nil {
 62→				return fmt.Errorf("failed reading provided config file: %s: %v", nbconfig.MgmtConfigPath, err)
 63→			}
 64→
 65→			if cmd.Flag(idpSignKeyRefreshEnabledFlagName).Changed {
 66→				config.HttpConfig.IdpSignKeyRefreshEnabled = idpSignKeyRefreshEnabled
 67→			}
 68→
 69→			var tlsEnabled bool
 70→			if mgmtLetsencryptDomain != "" || (config.HttpConfig.CertFile != "" && config.HttpConfig.CertKey != "") {
 71→				tlsEnabled = true
 72→			}
 73→
 74→			if !userPort {
 75→				// different defaults for port when tls enabled/disabled
 76→				if tlsEnabled {
 77→					mgmtPort = 443
 78→				} else {
 79→					mgmtPort = 80
 80→				}
 81→			}
 82→
 83→			if !nbdomain.IsValidDomainNoWildcard(dnsDomain) {
 84→				return fmt.Errorf("invalid dns-domain: %s", dnsDomain)
 85→			}
 86→
 87→			return nil
 88→		},
 89→		RunE: func(cmd *cobra.Command, args []string) error {
 90→			flag.Parse()
 91→
 92→			ctx, cancel := context.WithCancel(cmd.Context())
 93→			defer cancel()
 94→			//nolint
 95→			ctx = context.WithValue(ctx, hook.ExecutionContextKey, hook.SystemSource)
 96→
 97→			err := handleRebrand(cmd)
 98→			if err != nil {
 99→				return fmt.Errorf("migrate files %v", err)
100→			}
101→
102→			if _, err = os.Stat(config.Datadir); os.IsNotExist(err) {
103→				err = os.MkdirAll(config.Datadir, 0755)
104→				if err != nil {
105→					return fmt.Errorf("failed creating datadir: %s: %v", config.Datadir, err)
106→				}
107→			}
108→
109→			if disableSingleAccMode {
110→				mgmtSingleAccModeDomain = ""
111→			}
112→
113→			srv := newServer(&server.Config{
114→				NbConfig:                    config,
115→				DNSDomain:                   dnsDomain,
116→				MgmtSingleAccModeDomain:     mgmtSingleAccModeDomain,
117→				MgmtPort:                    mgmtPort,
118→				MgmtMetricsPort:             mgmtMetricsPort,
119→				DisableLegacyManagementPort: disableLegacyManagementPort,
120→				DisableMetrics:              disableMetrics,
121→				DisableGeoliteUpdate:        disableGeoliteUpdate,
122→				UserDeleteFromIDPEnabled:    userDeleteFromIDPEnabled,
123→			})
124→			go func() {
125→				if err := srv.Start(cmd.Context()); err != nil {
126→					log.Fatalf("Server error: %v", err)
127→				}
128→			}()
129→
130→			stopChan := make(chan os.Signal, 1)
131→			signal.Notify(stopChan, os.Interrupt, syscall.SIGTERM)
132→			select {
133→			case <-stopChan:
134→				log.Info("Received shutdown signal, stopping server...")
135→				err = srv.Stop()
136→				if err != nil {
137→					log.Errorf("Failed to stop server gracefully: %v", err)
138→				}
139→			case err := <-srv.Errors():
140→				log.Fatalf("Server stopped unexpectedly: %v", err)
141→			}
142→
143→			return nil
144→		},
145→	}
146→)
