148→func LoadMgmtConfig(ctx context.Context, mgmtConfigPath string) (*nbconfig.Config, error) {
149→	loadedConfig := &nbconfig.Config{}
150→	if _, err := util.ReadJsonWithEnvSub(mgmtConfigPath, loadedConfig); err != nil {
151→		return nil, err
152→	}
153→
154→	ApplyCommandLineOverrides(loadedConfig)
155→
156→	// Apply EmbeddedIdP config to HttpConfig if embedded IdP is enabled
157→	err := ApplyEmbeddedIdPConfig(ctx, loadedConfig)
158→	if err != nil {
159→		return nil, err
160→	}
161→
162→	if err := ApplyOIDCConfig(ctx, loadedConfig); err != nil {
163→		return nil, err
164→	}
165→
166→	LogConfigInfo(loadedConfig)
167→
168→	if err := EnsureEncryptionKey(ctx, mgmtConfigPath, loadedConfig); err != nil {
169→		return nil, err
170→	}
171→
172→	return loadedConfig, nil
173→}
