189→// ApplyEmbeddedIdPConfig populates HttpConfig and EmbeddedIdP storage from config when embedded IdP is enabled.
190→// This allows users to only specify EmbeddedIdP config without duplicating values in HttpConfig.
191→func ApplyEmbeddedIdPConfig(ctx context.Context, cfg *nbconfig.Config) error {
192→	if cfg.EmbeddedIdP == nil || !cfg.EmbeddedIdP.Enabled {
193→		return nil
194→	}
195→
196→	// apply some defaults based on the EmbeddedIdP config
197→	if disableSingleAccMode {
198→		// Embedded IdP requires single account mode - multiple account mode is not supported
199→		return fmt.Errorf("embedded IdP requires single account mode; multiple account mode is not supported with embedded IdP. Please remove --disable-single-account-mode flag")
200→	}
201→	// Enable user deletion from IDP by default if EmbeddedIdP is enabled
202→	userDeleteFromIDPEnabled = true
203→
204→	// Set LocalAddress for embedded IdP if enabled, used for internal JWT validation
205→	cfg.EmbeddedIdP.LocalAddress = fmt.Sprintf("localhost:%d", mgmtPort)
206→
207→	// Set storage defaults based on Datadir
208→	if cfg.EmbeddedIdP.Storage.Type == "" {
209→		cfg.EmbeddedIdP.Storage.Type = "sqlite3"
210→	}
211→	if cfg.EmbeddedIdP.Storage.Config.File == "" && cfg.Datadir != "" {
212→		cfg.EmbeddedIdP.Storage.Config.File = path.Join(cfg.Datadir, "idp.db")
213→	}
214→
215→	issuer := cfg.EmbeddedIdP.Issuer
216→
217→	if cfg.HttpConfig != nil {
218→		log.WithContext(ctx).Warnf("overriding HttpConfig with EmbeddedIdP config. " +
219→			"HttpConfig is ignored when EmbeddedIdP is enabled. Please remove HttpConfig section from the config file")
220→	} else {
221→		// Ensure HttpConfig exists. We need it for backwards compatibility with the old config format.
222→		cfg.HttpConfig = &nbconfig.HttpServerConfig{}
223→	}
224→
225→	// Set HttpConfig values from EmbeddedIdP
226→	cfg.HttpConfig.AuthIssuer = issuer
227→	cfg.HttpConfig.AuthAudience = "netbird-dashboard"
228→	cfg.HttpConfig.AuthClientID = cfg.HttpConfig.AuthAudience
229→	cfg.HttpConfig.CLIAuthAudience = "netbird-cli"
230→	cfg.HttpConfig.AuthUserIDClaim = "sub"
231→	cfg.HttpConfig.AuthKeysLocation = issuer + "/keys"
232→	cfg.HttpConfig.OIDCConfigEndpoint = issuer + "/.well-known/openid-configuration"
233→	cfg.HttpConfig.IdpSignKeyRefreshEnabled = true
234→	callbackURL := strings.TrimSuffix(cfg.HttpConfig.AuthIssuer, "/oauth2")
235→	cfg.HttpConfig.AuthCallbackURL = callbackURL + types.ProxyCallbackEndpointFull
236→
237→	return nil
238→}
