240→// ApplyOIDCConfig fetches and applies OIDC configuration if endpoint is specified
241→func ApplyOIDCConfig(ctx context.Context, cfg *nbconfig.Config) error {
242→	oidcEndpoint := cfg.HttpConfig.OIDCConfigEndpoint
243→	if oidcEndpoint == "" {
244→		return nil
245→	}
246→
247→	if cfg.EmbeddedIdP != nil && cfg.EmbeddedIdP.Enabled {
248→		// skip OIDC config fetching if EmbeddedIdP is enabled as it is unnecessary given it is embedded
249→		return nil
250→	}
251→
252→	log.WithContext(ctx).Infof("loading OIDC configuration from the provided IDP configuration endpoint %s", oidcEndpoint)
253→	oidcConfig, err := fetchOIDCConfig(ctx, oidcEndpoint)
254→	if err != nil {
255→		return err
256→	}
257→	log.WithContext(ctx).Infof("loaded OIDC configuration from the provided IDP configuration endpoint: %s", oidcEndpoint)
258→
259→	log.WithContext(ctx).Infof("overriding HttpConfig.AuthIssuer with a new value %s, previously configured value: %s",
260→		oidcConfig.Issuer, cfg.HttpConfig.AuthIssuer)
261→	cfg.HttpConfig.AuthIssuer = oidcConfig.Issuer
262→
263→	log.WithContext(ctx).Infof("overriding HttpConfig.AuthKeysLocation (JWT certs) with a new value %s, previously configured value: %s",
264→		oidcConfig.JwksURI, cfg.HttpConfig.AuthKeysLocation)
265→	cfg.HttpConfig.AuthKeysLocation = oidcConfig.JwksURI
266→
267→	if err := ApplyDeviceAuthFlowConfig(ctx, cfg, &oidcConfig, oidcEndpoint); err != nil {
268→		return err
269→	}
270→	ApplyPKCEFlowConfig(ctx, cfg, &oidcConfig)
271→
272→	return nil
273→}
