275→// ApplyDeviceAuthFlowConfig applies OIDC config to DeviceAuthorizationFlow if enabled
276→func ApplyDeviceAuthFlowConfig(ctx context.Context, cfg *nbconfig.Config, oidcConfig *OIDCConfigResponse, oidcEndpoint string) error {
277→	if cfg.DeviceAuthorizationFlow == nil || strings.ToLower(cfg.DeviceAuthorizationFlow.Provider) == string(nbconfig.NONE) {
278→		return nil
279→	}
280→
281→	log.WithContext(ctx).Infof("overriding DeviceAuthorizationFlow.TokenEndpoint with a new value: %s, previously configured value: %s",
282→		oidcConfig.TokenEndpoint, cfg.DeviceAuthorizationFlow.ProviderConfig.TokenEndpoint)
283→	cfg.DeviceAuthorizationFlow.ProviderConfig.TokenEndpoint = oidcConfig.TokenEndpoint
284→
285→	log.WithContext(ctx).Infof("overriding DeviceAuthorizationFlow.DeviceAuthEndpoint with a new value: %s, previously configured value: %s",
286→		oidcConfig.DeviceAuthEndpoint, cfg.DeviceAuthorizationFlow.ProviderConfig.DeviceAuthEndpoint)
287→	cfg.DeviceAuthorizationFlow.ProviderConfig.DeviceAuthEndpoint = oidcConfig.DeviceAuthEndpoint
288→
289→	u, err := url.Parse(oidcEndpoint)
290→	if err != nil {
291→		return err
292→	}
293→	log.WithContext(ctx).Infof("overriding DeviceAuthorizationFlow.ProviderConfig.Domain with a new value: %s, previously configured value: %s",
294→		u.Host, cfg.DeviceAuthorizationFlow.ProviderConfig.Domain)
295→	cfg.DeviceAuthorizationFlow.ProviderConfig.Domain = u.Host
296→
297→	if cfg.DeviceAuthorizationFlow.ProviderConfig.Scope == "" {
298→		cfg.DeviceAuthorizationFlow.ProviderConfig.Scope = nbconfig.DefaultDeviceAuthFlowScope
299→	}
300→	return nil
301→}
