347→// OIDCConfigResponse used for parsing OIDC config response
348→type OIDCConfigResponse struct {
349→	Issuer                string `json:"issuer"`
350→	TokenEndpoint         string `json:"token_endpoint"`
351→	DeviceAuthEndpoint    string `json:"device_authorization_endpoint"`
352→	JwksURI               string `json:"jwks_uri"`
353→	AuthorizationEndpoint string `json:"authorization_endpoint"`
354→}
