356→// fetchOIDCConfig fetches OIDC configuration from the IDP
357→func fetchOIDCConfig(ctx context.Context, oidcEndpoint string) (OIDCConfigResponse, error) {
358→	res, err := http.Get(oidcEndpoint)
359→	if err != nil {
360→		return OIDCConfigResponse{}, fmt.Errorf("failed fetching OIDC configuration from endpoint %s %v", oidcEndpoint, err)
361→	}
362→
363→	defer func() {
364→		err := res.Body.Close()
365→		if err != nil {
366→			log.WithContext(ctx).Debugf("failed closing response body %v", err)
367→		}
368→	}()
369→
370→	body, err := io.ReadAll(res.Body)
371→	if err != nil {
372→		return OIDCConfigResponse{}, fmt.Errorf("failed reading OIDC configuration response body: %v", err)
373→	}
374→
375→	if res.StatusCode != 200 {
376→		return OIDCConfigResponse{}, fmt.Errorf("OIDC configuration request returned status %d with response: %s",
377→			res.StatusCode, string(body))
378→	}
379→
380→	config := OIDCConfigResponse{}
381→	err = json.Unmarshal(body, &config)
382→	if err != nil {
383→		return OIDCConfigResponse{}, fmt.Errorf("failed unmarshaling OIDC configuration response: %v", err)
384→	}
385→
386→	return config, nil
387→}
