389→func handleRebrand(cmd *cobra.Command) error {
390→	var err error
391→	if logFile == defaultLogFile {
392→		if migrateToNetbird(oldDefaultLogFile, defaultLogFile) {
393→			cmd.Printf("will copy Log dir %s and its content to %s\n", oldDefaultLogDir, defaultLogDir)
394→			err = cpDir(oldDefaultLogDir, defaultLogDir)
395→			if err != nil {
396→				return err
397→			}
398→		}
399→	}
400→	if nbconfig.MgmtConfigPath == defaultMgmtConfig {
401→		if migrateToNetbird(oldDefaultMgmtConfig, defaultMgmtConfig) {
402→			cmd.Printf("will copy Config dir %s and its content to %s\n", oldDefaultMgmtConfigDir, defaultMgmtConfigDir)
403→			err = cpDir(oldDefaultMgmtConfigDir, defaultMgmtConfigDir)
404→			if err != nil {
405→				return err
406→			}
407→		}
408→	}
409→	if mgmtDataDir == defaultMgmtDataDir {
410→		if migrateToNetbird(oldDefaultMgmtDataDir, defaultMgmtDataDir) {
411→			cmd.Printf("will copy Config dir %s and its content to %s\n", oldDefaultMgmtDataDir, defaultMgmtDataDir)
412→			err = cpDir(oldDefaultMgmtDataDir, defaultMgmtDataDir)
413→			if err != nil {
414→				return err
415→			}
416→		}
417→	}
418→	return nil
419→}
