421→func cpFile(src, dst string) error {
422→	var err error
423→	var srcfd *os.File
424→	var dstfd *os.File
425→	var srcinfo os.FileInfo
426→
427→	if srcfd, err = os.Open(src); err != nil {
428→		return err
429→	}
430→	defer srcfd.Close()
431→
432→	if dstfd, err = os.Create(dst); err != nil {
433→		return err
434→	}
435→	defer dstfd.Close()
436→
437→	if _, err = io.Copy(dstfd, srcfd); err != nil {
438→		return err
439→	}
440→	if srcinfo, err = os.Stat(src); err != nil {
441→		return err
442→	}
443→	return os.Chmod(dst, srcinfo.Mode())
444→}
445→
446→func copySymLink(source, dest string) error {
447→	link, err := os.Readlink(source)
448→	if err != nil {
449→		return err
450→	}
451→	return os.Symlink(link, dest)
452→}
453→
454→func cpDir(src string, dst string) error {
455→	var err error
456→	var fds []os.DirEntry
457→	var srcinfo os.FileInfo
458→
459→	if srcinfo, err = os.Stat(src); err != nil {
460→		return err
461→	}
462→
463→	if err = os.MkdirAll(dst, srcinfo.Mode()); err != nil {
464→		return err
465→	}
466→
467→	if fds, err = os.ReadDir(src); err != nil {
468→		return err
469→	}
470→	for _, fd := range fds {
471→		srcfp := path.Join(src, fd.Name())
472→		dstfp := path.Join(dst, fd.Name())
473→
474→		fileInfo, err := os.Stat(srcfp)
475→		if err != nil {
476→			log.Fatalf("Couldn't get fileInfo; %v", err)
477→		}
478→
479→		switch fileInfo.Mode() & os.ModeType {
480→		case os.ModeSymlink:
481→			if err = copySymLink(srcfp, dstfp); err != nil {
482→				log.Fatalf("Failed to copy from %s to %s; %v", srcfp, dstfp, err)
483→			}
484→		case os.ModeDir:
485→			if err = cpDir(srcfp, dstfp); err != nil {
486→				log.Fatalf("Failed to copy from %s to %s; %v", srcfp, dstfp, err)
487→			}
488→		default:
489→			if err = cpFile(srcfp, dstfp); err != nil {
490→				log.Fatalf("Failed to copy from %s to %s; %v", srcfp, dstfp, err)
491→			}
492→		}
493→	}
494→	return nil
495→}
496→
497→func migrateToNetbird(oldPath, newPath string) bool {
498→	_, errOld := os.Stat(oldPath)
499→	_, errNew := os.Stat(newPath)
500→
501→	if errors.Is(errOld, fs.ErrNotExist) || errNew == nil {
502→		return false
503→	}
504→
505→	return true
506→}
