656→	}
657→
658→	log.Info("  Auth (embedded IdP):")
659→	log.Infof("    Issuer: %s", cfg.Management.Auth.Issuer)
660→	log.Infof("    Dashboard redirect URIs: %v", cfg.Management.Auth.DashboardRedirectURIs)
661→	log.Infof("    CLI redirect URIs: %v", cfg.Management.Auth.CLIRedirectURIs)
662→
663→	log.Info("  Client settings:")
664→	log.Infof("    Signal URI: %s", cfg.Management.SignalURI)
665→	for _, s := range cfg.Management.Stuns {
666→		log.Infof("    STUN: %s", s.URI)
667→	}
668→	if len(cfg.Management.Relays.Addresses) > 0 {
669→		log.Infof("    Relay addresses: %v", cfg.Management.Relays.Addresses)
