				// LogLevel inherited from Server.LogLevel via ApplySimplifiedDefaults
			},
		},
		Signal: SignalConfig{
			// LogLevel inherited from Server.LogLevel via ApplySimplifiedDefaults
		},
		Management: ManagementConfig{
