func extractIdpType(connectorID string) string {
	if connectorID == "" {
		return "unknown"
	}
	idx := strings.LastIndex(connectorID, "-")
	if idx <= 0 {
		return strings.ToLower(connectorID)
	}
	return strings.ToLower(connectorID[:idx])
}

